      <span>\n                            Detaylı Bilgi\n                        </span>\n                  <i class=\"ri-arrow-right-s-line\"></i>\n                </a>\n              \n            </div>\n          </div>\n        \n      </div>\n\n      <div class=\"d-flex justify-content-center  d-md-none\">\n        <a href=\"#\" title=\"Etkinlikler\" class=\"btn-show-more mt-4\">\n          Tüm Etkinlikler\n          <i class=\"ri-arrow-down-s-line\"></i>\n        </a>\n      </div>\n    </div>\n\n    <section class=\"podcasts\" style=\"margin-top: 60px;margin-bottom: 60px\">\n      <div class=\"container\">\n        <div class=\"row\">\n\n          <div class=\"col-md-8 offset-md-2\">\n            <div class=\"primary-title primary-title-md--center\">\n              <i class=\"ri-spotify-fill\"></i>\n\n              <h3>Codecast: Yazılımcı Sohbetleri</h3>\n              <p>Farklı alanlardan konuklarımızın katılımlarıyla gerçekleşen Codecast’te yazılım ve veri bilimi yöneticilerini Podcast serimizde konuk ediyoruz!</p>\n            </div>\n          </div>\n          <div class=\"col-12\">\n            <div class=\"swiper-container\">\n              <div class=\"swiper-wrapper\">\n                \n                \n\n              </div>\n            </div>\n            <div class=\"answers-button\">\n              <a href=\"/podcast\" class=\"primary-button primary-button--big\">\n                <span>Hemen Dinlemeye Başla</span>\n                <i class=\"ri-arrow-right-s-line\"></i>\n              </a>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n    \n\n  </section>\n\n\n\n\n    \n    <script type=\"text/javascript\" language=\"javascript\"\n      src=\"https://ajax.googleapis.com/ajax/libs/jquery/3.5.1/jquery.min.js\"></script>\n    \n    <!-- Chat -->\n    \n\n    <!-- Google Tag Manager (noscript) -->\n    <noscript>\n      <iframe src=\"https://www.googletagmanager.com/ns.html?id=GTM-NKNKD22\" height=\"0\" width=\"0\"\n        style=\"display:none;visibility:hidden\"></iframe>\n    </noscript>\n    <!-- End Google Tag Manager (noscript) -->\n    \n\n\n\n\n\n<script>\n  class EventPopupManager {\n    constructor() {\n      this.cookiePrefix = \'event_popup_\';\n      this.popupInterval = 3 * 24 * 60 * 60 * 1000; // 3 days in milliseconds\n      this.initialize();\n    }\n\n    initialize() {\n      const overlay = document.createElement(\'div\');\n      overlay.className = \'event-popup-overlay\';\n\n      const container = document.createElement(\'div\');\n      container.className = \'event-popup-container\';\n\n      const content = document.createElement(\'div\');\n      content.className = \'event-popup-content\';\n\n      container.appendChild(content);\n      overlay.appendChild(container);\n      document.body.appendChild(overlay);\n\n      this.overlay = overlay;\n      this.content = content;\n\n      // Close popup when clicking outside\n      overlay.addEventListener(\'click\', (e) => {\n        if (e.target === overlay) this.hidePopup();\n      });\n\n      // Escape key to close\n      document.addEventListener(\'keydown\', (e) => {\n        if (e.key === \'Escape\') this.hidePopup();\n      });\n\n      this.checkEvents();\n    }\n\n    getCookie(eventId) {\n      const name = this.cookiePrefix + eventId;\n      const value = `; ${document.cookie}`;\n      const parts = value.split(`; ${name}=`);\n      if (parts.length === 2) return parts.pop().split(\';\').shift();\n      return null;\n    }\n\n    setCookie(eventId, value) {\n      const name = this.cookiePrefix + eventId;\n      const date = new Date();\n      date.setTime(date.getTime() + this.popupInterval);\n      document.cookie = `${name}=${value};expires=${date.toUTCString()};path=/`;\n    }\n\n    checkEvents() {\n      const unpaidEvents = document.querySelectorAll(\'[data-event-id]\');\n      const now = new Date().getTime();\n\n      for (const eventElement of unpaidEvents) {\n        const eventId = eventElement.getAttribute(\'data-event-id\');\n        const lastShown = this.getCookie(eventId);\n\n        if (!lastShown || now - parseInt(lastShown) >= this.popupInterval) {\n          this.content.innerHTML = this.generatePopupContent(eventElement);\n\n          // Add close button event listener\n          const closeBtn = this.content.querySelector(\'.event-popup-close\');\n          if (closeBtn) {\n            closeBtn.onclick = () => this.hidePopup();\n          }\n\n          this.showPopup();\n          this.setCookie(eventId, now.toString());\n          break;\n        }\n      }\n    }\n\n    generatePopupContent(eventElement) {\n      const image = eventElement.querySelector(\'img\').cloneNode(true);\n      image.className = \'event-popup-image\';\n      const name = eventElement.querySelector(\'.event-name\').textContent;\n      const badgesList = eventElement.querySelector(\'.hiring-challange-main-inner-info\').cloneNode(true);\n      const eventUrl = eventElement.getAttribute(\'data-event-url\');\n      // Update price display\n      this.updatePriceDisplay(badgesList);\n\n      return `\n      <div class=\"event-popup-header\">\n        ${image.outerHTML}\n        <div class=\"event-popup-close\">✕</div>\n      </div>\n      <div class=\"event-popup-content\">\n        <div class=\"event-popup-badges\">\n          ${badgesList.outerHTML}\n        </div>\n        <div class=\"event-popup-title\">${name}</div>\n        <a href=\"${eventUrl}\" style=\"color:white\" class=\"event-popup-button\">\n          Ödemeni Tamamla\n          <i class=\"ri-arrow-right-s-line\"></i>\n        </a>\n      </div>\n    `;\n    }\n\n    updatePriceDisplay(badgesList) {\n      const priceBadge = badgesList.querySelector(\'[data-price-badge]\');\n      if (priceBadge) {\n        const priceElement = priceBadge.querySelector(\'strong\');\n        const currentPrice = priceElement.getAttribute(\'data-current-price\');\n        const nextPrice = priceElement.getAttribute(\'data-next-price\');\n\n        if (nextPrice) {\n          priceElement.innerHTML = \'\';\n\n          // old price\n          const oldPriceSpan = document.createElement(\'span\');\n          oldPriceSpan.className = \'old-price\';\n          oldPriceSpan.textContent = `₺${nextPrice}`;\n          priceElement.appendChild(oldPriceSpan);\n\n          // new price\n          const currentPriceSpan = document.createElement(\'span\');\n          currentPriceSpan.className = \'current-price\';\n          currentPriceSpan.textContent = `₺${currentPrice}`;\n          priceElement.appendChild(currentPriceSpan);\n        }\n      }\n    }\n\n    showPopup() {\n      this.overlay.style.display = \'flex\';\n      document.body.style.overflow = \'hidden\'; // Prevent background scrolling\n    }\n\n    hidePopup() {\n      this.overlay.style.display = \'none\';\n      document.body.style.overflow = \'\'; // Restore scrolling\n    }\n  }\n\n  // Initialize popup manager when DOM is loaded\n  document.addEventListener(\'DOMContentLoaded\', () => {\n    new EventPopupManager();\n  });\n\n</script>\n\n    \n      \n         \n\n<style>\n.turkish-liras::before {\n  content: \"\\20BA\";\n}\n</style>\n\n\n\n<div\n  class=\"modal fade modal-landscape   \"\n  id=\"careerRoleNotification-436\"\n  tabindex=\"-1\"\n  role=\"dialog\"\n  aria-labelledby=\"careerRoleNotificationModal\"\n  aria-hidden=\"true\"\n>\n  <div class=\"modal-dialog modal-dialog-centered\" role=\"document\">\n    <div class=\"modal-content\">\n      <div class=\"modal-imageWrapper\">\n        \n        \n           <img src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/media/cache/8b/28/8b286c7891a135754b3dc924b0138065.webp\" srcset=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/media/cache/8b/28/8b286c7891a135754b3dc924b0138065.webp 1x\" alt=\"popupimage\"/>\n        \n\n      \n      </div>\n\n      <div class=\"modal-header\">\n        <h6 class=\"h4 font-inter\">Python ö