 * 24 * 60 * 60 * 1000;\n  const now = Date.now();\n  const expires = now + cookieAge;\n  const expiresDate = new Date(expires);\n\n(function(popupId) {\n  const cookieName = `csViewedCareerRoleNotification-${popupId}`;\n  const cookieValue = cookies.get(cookieName);\n  const modalSelector = `#careerRoleNotification-${popupId}`;\n\n  if (!cookieValue) {\n    $(modalSelector).modal(\'show\');\n\n    const expires = new Date(now + cookieAge);\n    cookies.set(cookieName, \'viewed\', {\n      expires: expires,\n      path: \'/\'\n    });\n\n    $.ajax({\n      type: \"PUT\",\n      url: \"/popups/api/increase_viewed_count/\",\n      headers: {\"X-CSRFToken\": \'U19HQXRwPZqQltmkFGPPZ5V9BvJx9om39ai0WvTOHpsucVOdPs6XoYhAZRFlqye9\'},\n      data: {popup_id: popupId}\n    });\n  }\n})(436);\n\n</script>\n\n\n    <!-- Footer -->\n    \n    \n\n\n<footer class=\"footer\">\n  \n    \n    \n    \n    \n    \n  \n  <div class=\"footer-bottom pt-10 mt-5 mt-md-0\">\n    <div class=\"container\">\n      <div class=\"row\">\n        <div class=\"col-12 col-sm-12 col-lg-4\">\n          <div class=\"footer-bottom-info\">\n\n            <img src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/img/brand/coderspace-white-logo.svg\" alt=\"Coderspace Logo\" width=\"180\" height=\"30\">\n\n            <p>\n              Öğren, kodla, yarış, kariyer fırsatlarını yakala. Coderspace her adımda yanında.\n            </p>\n            <ul class=\"nav justify-content-center justify-content-md-start mt-3 mt-md-0\">\n              <li class=\"nav-item\">\n                <a class=\"nav-link\" aria-label=\"Instagram\" title=\"Instagram\" href=\"https://instagram.com/coderspaceio\" target=\"_blank\" style=\"\n                  padding-left: 0 \">\n                  <i class=\"fab fa-instagram fa-lg\" style=\"color: unset\"></i>\n                </a>\n              </li>\n              <li class=\"nav-item\">\n                <a class=\"nav-link\" rel=\"nofollow\" aria-label=\"Li