              <li><a href=\"/assessment-hub\">Assessment Hub</a></li>\n                \n                <li><a href=\"/tersine-beyin-gocu/\">Tersine Beyin Göçü</a></li>\n                \n                \n                <li><a href=\"/basari-hikayeleri/\">Başarı Hikayeleri</a></li>\n                <li><a href=\"/e-kitaplar/\">E-kitaplar</a></li>\n                \n                <li><a href=\"/webinar/\">HR Webinarları</a></li>\n                \n                <li><a href=\"/ik-hesaplama-araclari/\">İK Hesaplama Araçları</a></li>\n                \n              </ul>\n            </div>\n            <div class=\"footer-bottom-nav-item mt-md-0\">\n              <h6>Kurumsal</h6>\n              <ul>\n                <li><a href=\"/bize-katil\" rel=\"nofollow\">Bize Katıl</a></li>\n                <li><a href=\"/iletisim\">İletişim</a></li>\n                <li><a href=\"/yardim-merkezi/\">Yardım Merkezi</a></li>\n                <li><a href=\"/kvkk\">KVKK</a></li>\n                <li><a href=\"/kullanicisozlesmesi\">Kullanıcı Sözleşmesi</a></li>\n                <li><a href=\"/gizlilik\">Gizlilik Sözleşmesi</a></li>\n              </ul>\n            </div>\n          </nav>\n        </div>\n\n        <div class=\"payment-img-qr\">\n          <img src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/img/payment.webp\" class=\"payment-img\" alt=\"payment\" width=\"70\" height=\"70\">\n          <div id=\"ETBIS\"><div id=\"2603348280428323\"><a href=\"https://etbis.eticaret.gov.tr/sitedogrulama/2603348280428323\" target=\"_blank\"><img alt=\"etbis qr\" class=\"payment-qr\" style=\'opacity: 0.6;\' src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/img/etbis.webp\"/></a></div></div>\n        </div>\n\n        <div class=\"col-12 col-sm-12\">\n          <div class=\"footer-bottom-text mt-4\">\n            <div>\n              <div class=\"media\">\n                <img class=\"d-flex mr-1\" width=\"50\" height=\"35\" alt=\"Generic placeholder image\" src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/img/brand/oiblogo.webp\"\n                  style=\"height: 35px\">\n                <div class=\"media-body mt-2\" style=\"font-weight: 100; font-size: 10px;\">\n                  CS İnsan Kaynakları Tanıtım ve Danışmanlık A.Ş. Özel İstihdam Bürosu Olarak 18.03.2026 – 17.03.2029 tarihleri arasında faaliyette bulunmak üzere, Türkiye İş Kurumu’nun 19.03.2026 tarih ve 1151 numaralı aracılık izin belgesi ile faaliyet göstermektedir. 4904 sayılı Kanun uyarınca iş arayanlardan ücret alınması yasaktır. </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</footer>\n\n    \n\n    <!-- Core JS - includes jquery, bootstrap, popper, in-view and sticky-kit -->\n    <script src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/CACHE/js/output.63e17ccdbf0e.js\"></script>\n    \n  \n  <script>\n    \n      document.getElementById(\'navbar-register-btn\').href = \"/kayitol?utm_source=cs&utm_medium=sozluk&utm_campaign=13\"\n    \n    window.addEventListener(\'load\', function () {\n      var cloneSidebar = document.querySelector(\'.glossary-sidebar\').cloneNode(true);\n      cloneSidebar.classList.remove(\'desktop-sidebar\');\n      cloneSidebar.classList.add(\'mobile-sidebar\');\n      cloneSidebar.classList.add(\'container\');\n      $(\".glossary-detail\").append(cloneSidebar);\n    });\n\n  </script>\n<script>\n  const articleTextToCopy = `Bu makaleyi özetle:  ${window.location.href}`\n</script>\n  <script src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/js/ai_summarize_card.js\"></script>\n  \n    \n\n\n<div class=\"modal fade\" id=\"registerModal\" tabindex=\"-1\" role=\"dialog\" aria-labelledby=\"registerModal\"\n     aria-hidden=\"true\">\n  <div class=\"modal-dialog\" role=\"document\">\n    <div class=\"modal-content\">\n      <div class=\"modal-header\">\n        <h5 class=\"modal-title\" id=\"registerModal\">Kayıt Ol</h5>\n        <button type=\"button\" class=\"close\" data-dismiss=\"modal\" aria-label=\"Close\">\n          <span aria-hidden=\"true\">&times;</span>\n        </button>\n      </div>\n      <div class=\"modal-body\">\n        <div class=\"text-center\">\n        <img src=\"https://coderspace-storage-prod.s3.eu-central-1.amazonaws.com/static/img/icons/astronot_pc.webp\" alt=\"rocket\" class=\"img-fluid\" style=\"max-width: 50%\">\n          </div>\n        <br>\n        <p class=\"text-center\" style=\"font-size: 18px\">Kodla, yarışmalara katıl, kendini geliştir. Coderspace seni en uygun şirketlerle eşleştirsin.🚀</p>\n      </div>\n      <div class=\"modal-footer text-center\">\n        \n            <a href=\"/kayitol?utm_source=Google&utm_medium=sozlukkayitsiz&utm_campaign=sozluk+popup\" class=\"w-100\"><button type=\"button\" class=\"btn btn-primary w-100\">Ücretsiz Kayıt Ol</button></a>\n        \n      </div>\n    </div>\n  </div>\n</div>\n\n    <script>\n\n  function getCookieValue(cookieName) {\n    let name = cookieName + \"=\";\n    let decodedCookie = decodeURIComponent(document.cookie);\n    let cookieArray = decodedCookie.split(\';\');\n    for (let i = 0; i < cookieArray.length; i++) {\n      let cookie = cookieArray[i];\n      while (cookie.charAt(0) === \' \') {\n        cookie = cookie.substring(1);\n      }\n      if (cookie.indexOf(name) === 0) {\n        return cookie.substring(name.length, cookie.length);\n      }\n    }\n    return null;\n  }\n\n\n  function checkAndSetVisitedCookie() {\n    let cookieName = \"visitedPage\";\n    let expirationDays = 7;\n\n    if (document.cookie.indexOf(cookieName) === -1) {\n      \n        let d = new Date();\n        d.setTime(d.getTime() + (expirationDays * 24 * 60 * 60 * 1000));\n        let expires = \"expires=\" + d.toUTCString();\n        document.cookie = cookieName + \"=false;\" + expires + \";path=/\";\n      \n    } else if (getCookieValue(cookieName) === \"false\") {\n      $(\'#registerModal\').modal(\'show\');\n      let d = new Date();\n      d.setTime(d.getTime() + (expirationDays * 24 * 60 * 60 * 1000));\n      let expires = \"expires=\" + d.toUTCString();\n      document.cookie = cookieName + \"=true;\" + expires + \";path=/\";\n    }\n  }\n\n  checkAndSetVisitedCookie()\n\n</script>\n\n  \n\n\n\n\n    \n  <script>\n        $(function () {\n  $(document).scroll(function () {\n    var $nav = $(\".navbar-fixed-top\");\n    $nav.toggleClass(\'scrolled\', $(this).scrollTop() > $nav.height());\n\n    $nav.parent().parent().toggleClass($nav.parent().parent().hasClass(\"dark-header-fixed-toggler\") && \'dark-header-bc\', $(this).scrollTop() <= $nav.height());\n  });\n});\n\ndocument.addEventListener(\"DOMContentLoaded\", function () {\n      const mainNav = document.querySelector(\".main-navbar\");\n      if(mainNav){\n        let mainNavHeight = mainNav.offsetHeight;\n        mainNav.style.height = mainNavHeight + \"px\";\n        document.body.style.marginTop =  mainNavHeight + \"px\";\n\n        document.addEventListener(\"scroll\", function () {\n        if (window.scrollY > mainNavHeight) {\n          mainNav.classList.add(\"scrolled\");\n\n        } else {\n          mainNav.classList.remove(\"scrolled\");\n\n\n        }\n      });\n\n        if (mainNav.querySelector(\"#closeTopNavBtn\")){\n               mainNav.querySelector(\"#closeTopNavBtn\").addEventListener(\"click\", function () {\n       mainNav.parentElement.style.top = 0 + \"px\";\n       document.body.style.marginTop =  0 + \"px\";\n     });\n\n        }\n\n\n     let initialWidth = window.innerWidth;\n     let isStarted = false;\n      window.addEventListener(\"resize\", function () {\n        if (isStarted || initialWidth === window.innerWidth) {\n          return;\n        }\n        initialWidth = window.innerWidth;\n        isStarted = true;\n        setTimeout(() => {\n          mainNav.style.height = \"unset\";\n          mainNavHeight = mainNav.offsetHeight;\n          document.body.style.marginTop =  mainNavHeight + \"px\";\n          mainNav.style.height = mainNavHeight + \"px\";\n          isStarted = false;\n        }, 400)\n\n\n\n      })\n\n      }\n\n    });\n\n    </script>\n\n\n    \n  \n  </body>\n\n</html>\n', 'off');
